const sessionId = $input.first().json.query.sid;
const action = $input.first().json.query.a;
const staticData = $getWorkflowStaticData('global');
const session = staticData.sessions[sessionId];

const plan = session.plan;
const week1 = plan.weeks[0];
const toughTopics = week1.topics.filter(t => week1.difficulty >= 4).join(', ') || "No major boss fights!";

const week1Email = `<div style="font-family:sans-serif; padding:20px; border:2px solid #4f46e5;"><h3>🤖 Study Buddy</h3><p>Course: ${plan.course_name}</p><p><b>Tough Topics:</b> ${toughTopics}</p></div>`;

const events = plan.weeks.map((w, i) => {
  let start = new Date();
  start.setDate(start.getDate() + (i * 7));
  return {
    summary: `📚 Buddy Session: ${w.theme}`,
    description: `Focus on: ${w.topics.join(', ')}`,
    start: start.toISOString(),
    end: new Date(start.getTime() + 7200000).toISOString()
  };
});

return [{ json: { week1Email, events, studentEmail: "jainishbaria42@gmail.com" } }];
